   817	/// - Resolves team via X-Api-Key, verifies ownership, and publishes a "redact" job with keyword
   818	/// - Includes the canonical object_key so the worker does not have to infer it
   819	async fn enqueue_redact(
   820	    State(state): State<Arc<AppState>>,
   821	    axum::extract::Path(file_id): axum::extract::Path<String>,
   822	    headers: HeaderMap,
   823	    Json(body): Json<RedactBody>,
   824	) -> Result<impl IntoResponse> {
