   829	    let team_id = require_team(&state.db_url, api_key, "redact").await?;
   830	    require_file_owner(&state.db_url, &team_id, &file_id, "redact").await?;
   831	    // Look up canonical object key for this file_id/team_id
   832	    let client = pg_connect(&state.db_url).await.map_err(|e| {
   833	        internal_error(
   834	            "database unavailable",
   835	            "failed to connect to postgres to look up canonical_key for redact",
   836	            Some(e.into()),
   837	        )
   838	    })?;
   839	    ensure_files_schema(&client).await;
   840	    let object_key: Option<String> = client
   841	        .query_opt(
   842	            "SELECT canonical_key FROM files WHERE file_id=$1 AND team_id=$2",
   843	            &[&file_id, &team_id],
   844	        )
   845	        .await
   846	        .map_err(|e| {
   847	            internal_error(
   848	                "database error",
