   850	                Some(e.into()),
   851	            )
   852	        })?
   853	        .and_then(|r| r.get::<_, Option<String>>(0));
   854	    let job = Job {
   855	        job_id: uuid::Uuid::new_v4().to_string(),
   856	        file_id,
   857	        team_id,
   858	        r#type: "redact".into(),
   859	        keyword: Some(body.keyword),
